 13	import HelpTextIcon from '@kubevirt-utils/components/HelpTextIcon/HelpTextIcon';
 14	import TabModal from '@kubevirt-utils/components/TabModal/TabModal';
 15	import { documentationURL } from '@kubevirt-utils/constants/documentation';
 16	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 17	import {
 18	  DEFAULT_INSTANCETYPE_LABEL,
 19	  DEFAULT_PREFERENCE_LABEL,
 20	} from '@kubevirt-utils/resources/bootableresources/constants';
 21	import { convertResourceArrayToMap } from '@kubevirt-utils/resources/shared';
 22	import { ANNOTATIONS } from '@kubevirt-utils/resources/template';
 23	import { readableSizeUnit } from '@kubevirt-utils/utils/units';
 24	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
 25	import {
 26	  Form,
 27	  FormGroup,
 28	  Grid,
 29	  GridItem,
 30	  PopoverPosition,
 31	  SelectOption,
 32	  TextArea,
 33	} from '@patternfly/react-core';
 34	
 35	import { BootableResource, BootableVolumeMetadata } from '../../utils/types';
 36	import { changeBootableVolumeMetadata } from '../../utils/utils';
 37	
 38	type EditBootableVolumesModalProps = {
 39	  isOpen: boolean;
 40	  onClose: () => void;
 41	  preferences: V1beta1VirtualMachineClusterPreference[];
 42	  source: BootableResource;
 43	};
 44	
 45	const EditBootableVolumesModal: FC<EditBootableVolumesModalProps> = ({
 46	  isOpen,
 47	  onClose,
 48	  preferences,
 49	  source,
 50	}) => {
 51	  const { t } = useKubevirtTranslation();
 52	
 53	  const preferencesNames = useMemo(
 54	    () => Object.keys(convertResourceArrayToMap(preferences)).sort((a, b) => a.localeCompare(b)),
 55	    [preferences],
 56	  );
 57	
 58	  const initialParams = useMemo(() => {
 59	    const instanceTypeLabel = source?.metadata?.labels?.[DEFAULT_INSTANCETYPE_LABEL]?.split('.');
 60	    const initialCategory = Object.entries(categoryDetailsMap).find(
 61	      (category) => category[1].prefix === instanceTypeLabel?.[0],
 62	    );
 63	
 64	    return {
 65	      description: source?.metadata?.annotations?.[ANNOTATIONS.description],
 66	      instanceType: initialCategory,
 67	      preference: source?.metadata?.labels?.[DEFAULT_PREFERENCE_LABEL],
 68	      size: initialCategory && instanceTypeLabel?.[1],
 69	    };
 70	  }, [source]);
 71	
 72	  const [preference, setPreference] = useState<string>(initialParams.preference);
 73	  const [instanceType, setInstanceType] = useState<string>(initialParams.instanceType?.[0]);
 74	  const [size, setSize] = useState<string>(initialParams.size);
 75	  const [description, setDescription] = useState<string>(initialParams.description);
 76	
 77	  // update options for 'Size' dropdown according to chosen 'instanceType' in 'Default InstanceType' dropdown
 78	  const { instanceTypes }: CategoryDetails = useMemo(
 79	    () => (instanceType ? categoryDetailsMap[instanceType] : {}),
 80	    [instanceType],
 81	  );
 82	
 83	  const onInstanceTypeSelect = (_event: MouseEvent<HTMLSelectElement>, newInstanceType: string) => {
 84	    setInstanceType(newInstanceType);
 85	
 86	    const newCategoryObject = categoryDetailsMap[newInstanceType];
 87	    const newCategorySize = newCategoryObject.instanceTypes[0].label;
 88	    setSize(newCategorySize);
 89	  };
