103	    const descriptionAnnotation = description?.trim()
104	      ? { [ANNOTATIONS.description]: description.trim() }
105	      : { [ANNOTATIONS.description]: undefined }; // we do want undefined here to get the annotation removed from the resource, if description not provided
106	
107	    const metadata: BootableVolumeMetadata = {
108	      annotations: {
109	        ...source?.metadata?.annotations,
110	        ...descriptionAnnotation,
111	      },
112	      labels: {
113	        ...source?.metadata?.labels,
114	        ...preferenceLabel,
115	        ...instanceLabel,
116	      },
117	    };
118	
119	    return changeBootableVolumeMetadata(source, metadata);
120	  }, [source, description, instanceType, preference, size]);
121	
122	  return (
123	    <TabModal<K8sResourceCommon>
124	      headerText={t('Edit volume metadata')}
125	      isOpen={isOpen}
126	      obj={source}
127	      onClose={onClose}
128	      onSubmit={onSubmitVolumeParams()}
129	    >
130	      <Form>
131	        <FormGroup
132	          label={
133	            <>
134	              {t('Preference')}{' '}
135	              <HelpTextIcon
136	                bodyContent={
137	                  <>
138	                    {t(
139	                      'The preferred VirtualMachine attribute values required to run a given workload.',
140	                    )}{' '}
141	                    <ExternalLink
142	                      href={documentationURL.INSTANCE_TYPES_USER_GUIDE}
143	                      text={t('Read more')}
144	                    />
145	                  </>
146	                }
147	                position={PopoverPosition.right}
148	              />
149	            </>
150	          }
151	          isRequired
152	        >
153	          <InlineFilterSelect
154	            options={preferencesNames?.map((opt) => ({
155	              children: opt,
156	              groupVersionKind: VirtualMachineClusterPreferenceModelGroupVersionKind,
157	              value: opt,
158	            }))}
159	            selected={preference}
160	            setSelected={setPreference}
161	            toggleProps={{ placeholder: t('Select preference') }}
162	          />
163	        </FormGroup>
164	        <Grid hasGutter>
165	          <GridItem span={6}>
166	            <FormGroup
167	              label={
168	                <>
169	                  {t('Default InstanceType')}{' '}
170	                  <HelpTextIcon
171	                    bodyContent={t('The default InstanceType for this volume.')}
172	                    position={PopoverPosition.right}
173	                  />
174	                </>
175	              }
176	            >
177	              <FormPFSelect onSelect={onInstanceTypeSelect} selected={instanceType}>
178	                {Object.keys(InstanceTypeCategory)?.map((instanceTypeCategory) => {
179	                  const { seriesLabel, title }: CategoryDetails =
180	                    categoryDetailsMap[instanceTypeCategory];
181	                  return (
182	                    <SelectOption
183	                      description={title}
184	                      key={instanceTypeCategory}
185	                      value={instanceTypeCategory}
186	                    >
187	                      {seriesLabel}
188	                    </SelectOption>
189	                  );
190	                })}
191	              </FormPFSelect>
192	            </FormGroup>
193	          </GridItem>
194	          <GridItem span={6}>
195	            <FormGroup label={t('Size')}>
196	              <FormPFSelect onSelect={onSizeSelect} selected={size}>
197	                {instanceTypes?.map(({ cpus, label, memory }) => (
198	                  <SelectOption
199	                    description={t('{{cpus}} CPUs, {{memory}} Memory', {
200	                      cpus,
201	                      memory: readableSizeUnit(memory),
202	                    })}
203	                    key={label}
204	                    value={label}
205	                  >
206	                    {label}
207	                  </SelectOption>
208	                ))}
209	              </FormPFSelect>
210	            </FormGroup>
211	          </GridItem>
212	        </Grid>
213	        <FormGroup label={t('Description')}>
214	          <TextArea
215	            aria-label={t('description text area')}
216	            onChange={(_event, val) => setDescription(val)}
217	            resizeOrientation="vertical"
218	            value={description}
219	          />
220	        </FormGroup>
221	      </Form>
222	    </TabModal>
223	  );
224	};
225	
226	export default EditBootableVolumesModal;

