 1	import React, { FC, useState } from 'react';
 2	
 3	import { MenuToggleProps, Select, SelectProps } from '@patternfly/react-core';
 4	
 5	import SelectToggle from '../toggles/SelectToggle';
 6	
 7	type FormPFSelectProps = Omit<SelectProps, 'isOpen' | 'toggle'> & {
 8	  closeOnSelect?: boolean;
 9	  selectedLabel?: any;
10	  toggleProps?: MenuToggleProps;
11	};
12	
13	const FormPFSelect: FC<FormPFSelectProps> = ({
14	  children,
15	  className,
16	  closeOnSelect = true,
17	  onSelect,
18	  selected,
19	  selectedLabel,
20	  toggleProps,
21	  ...props
22	}) => {
23	  const [isOpen, setIsOpen] = useState(false);
24	
25	  const onToggle = () => setIsOpen((prevIsOpen) => !prevIsOpen);
26	
27	  return (
28	    <Select
29	      onSelect={(event, value) => {
30	        onSelect && onSelect(event, value);
31	        closeOnSelect && setIsOpen(false);
32	      }}
33	      toggle={SelectToggle({
34	        isExpanded: isOpen,
35	        onClick: onToggle,
36	        selected: selectedLabel || selected || toggleProps?.placeholder,
37	        ...toggleProps,
38	      })}
39	      className={className}
40	      isOpen={isOpen}
41	      isScrollable
42	      onOpenChange={(open: boolean) => setIsOpen(open)}
43	      selected={selected}
44	      {...props}
45	    >
46	      {children}
47	    </Select>
48	  );
49	};
50	
51	export default FormPFSelect;

